// PDF parsing utility - using pdf-parse v1.x simple API
import { detectPdfSource, type SourceDetectionResult } from './detect-source';

async function parsePdf(buffer: Buffer): Promise<{ text: string; numpages: number }> {
  // Dynamic require to avoid build-time bundling issues
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  const pdfParse = require('pdf-parse');
  const result = await pdfParse(buffer);
  return { text: result.text, numpages: result.numpages };
}

export interface ParsedCreditData {
  scores: {
    transunion?: number;
    experian?: number;
    equifax?: number;
  };
  accounts: ParsedAccount[];
  negativeItems: ParsedNegativeItem[];
  inquiries: ParsedInquiry[];
  summary: {
    totalAccounts: number;
    openAccounts: number;
    closedAccounts: number;
    totalDebt: number;
    totalCreditLimit: number;
    utilizationPercent: number;
  };
  rawText: string;
  detectedSource?: SourceDetectionResult;
  consumerProfile?: ParsedConsumerProfile;
}

export interface ParsedConsumerProfile {
  names: Array<{
    firstName: string;
    middleName?: string;
    lastName: string;
    suffix?: string;
    bureau?: string;
  }>;
  addresses: Array<{
    street: string;
    city: string;
    state: string;
    zipCode: string;
    addressType?: string;
    dateReported?: Date;
    bureau?: string;
  }>;
  ssnLast4?: string;
  dateOfBirth?: Date;
  employers: Array<{
    name: string;
    dateReported?: Date;
    bureau?: string;
  }>;
}

export interface ParsedAccount {
  creditorName: string;
  accountNumber?: string;
  accountType?: string;
  accountStatus?: string;
  balance?: number;
  creditLimit?: number;
  highCredit?: number;
  monthlyPayment?: number;
  pastDueAmount?: number;
  paymentStatus?: string;
  dateOpened?: Date;
  dateReported?: Date;
  bureau?: string;
  isNegative: boolean;
  riskLevel?: string;
  remarks?: string;
  sourceText?: string;
}

export interface ParsedNegativeItem {
  itemType: string;
  creditorName: string;
  originalCreditor?: string;
  accountNumber?: string; // For linking to credit accounts
  amount?: number;
  dateReported?: Date;
  dateOfLastActivity?: Date; // For DOFD/obsolescence analysis
  dateOfFirstDelinquency?: Date;
  bureauStatedRemovalDate?: Date;
  bureau?: string;
  riskSeverity: string;
}

export interface ParsedInquiry {
  creditorName: string;
  inquiryDate?: Date;
  bureau?: string;
  inquiryType?: string;
}

// Bureau-specific metrics (matching PHP ParserController output)
export interface BureauMetrics {
  creditScore?: number;
  lenderRank?: string;
  scoreScale?: string;
  reportDate?: string;
  totalAccounts: number;
  openAccounts: number;
  closedAccounts: number;
  delinquent: number;
  derogatory: number;
  collection: number;
  balances: number;
  payments: number;
  publicRecords: number;
  inquiries: number;
}

export interface BureauSummary {
  transunion: BureauMetrics;
  experian: BureauMetrics;
  equifax: BureauMetrics;
}

// Credit utilization per bureau
export interface CreditUtilization {
  balance: number;
  limit: number;
  percent: number;
  rating: 'excellent' | 'good' | 'fair' | 'poor' | 'very_poor' | 'no_data';
}

export interface BureauCreditUtilization {
  transunion: CreditUtilization;
  experian: CreditUtilization;
  equifax: CreditUtilization;
  total: CreditUtilization;
}

// Two-year payment history summary per bureau
export interface PaymentHistorySummary {
  lateCount30: number;
  lateCount60: number;
  lateCount90: number;
  lateCount120: number;
  lateCount150: number;
  lateCount180: number;
  chargeOffCount: number;
  collectionCount: number;
  maxLateDays: number; // 0, 30, 60, 90, 120, 150, 180
}

// Derogatory account with per-bureau details
export interface DerogatoryAccount {
  creditorName: string;
  uniqueStatus: string;
  transunion: {
    accountStatus?: string;
    accountDate?: string;
    paymentStatus?: string;
    paymentHistory?: PaymentHistorySummary;
    dateOfFirstDelinquency?: Date;
    bureauStatedRemovalDate?: Date;
  };
  experian: {
    accountStatus?: string;
    accountDate?: string;
    paymentStatus?: string;
    paymentHistory?: PaymentHistorySummary;
    dateOfFirstDelinquency?: Date;
    bureauStatedRemovalDate?: Date;
  };
  equifax: {
    accountStatus?: string;
    accountDate?: string;
    paymentStatus?: string;
    paymentHistory?: PaymentHistorySummary;
    dateOfFirstDelinquency?: Date;
    bureauStatedRemovalDate?: Date;
  };
}

// Public record item
export interface PublicRecord {
  type: string;
  status: string;
  transunionFiled?: string;
  experianFiled?: string;
  equifaxFiled?: string;
}

// Personal information per bureau (matching PHP ParserController output)
export interface PersonalInfoPerBureau {
  name?: string;
  alsoKnownAs?: string[];
  formerName?: string[];
  dateOfBirth?: string;
  currentAddress?: string;
  previousAddresses?: string[];
  employers?: string[];
}

export interface BureauPersonalInfo {
  transunion: PersonalInfoPerBureau;
  experian: PersonalInfoPerBureau;
  equifax: PersonalInfoPerBureau;
}

// Personal information dispute types for generating dispute letters
export type PersonalInfoDisputeType =
  | 'name'
  | 'also_known_as'
  | 'former_name'
  | 'date_of_birth'
  | 'current_address'
  | 'previous_address'
  | 'employer';

export interface PersonalInfoDisputeItem {
  type: PersonalInfoDisputeType;
  bureau: 'transunion' | 'experian' | 'equifax';
  value: string;
}

// Inquiry dispute item for disputing credit inquiries
export interface InquiryDisputeItem {
  type: 'inquiry';
  creditorName: string;
  bureau?: 'transunion' | 'experian' | 'equifax';
  inquiryDate?: Date;
  inquiryType?: string;
  isPastFcraLimit: boolean;
  daysSinceInquiry?: number;
}

// Extended parsed data with bureau-specific details
export interface ExtendedParsedCreditData extends ParsedCreditData {
  bureauSummary?: BureauSummary;
  creditUtilization?: BureauCreditUtilization;
  derogatoryAccounts?: DerogatoryAccount[];
  publicRecords?: PublicRecord[];
  bureauPersonalInfo?: BureauPersonalInfo;
  personalInfoDisputes?: PersonalInfoDisputeItem[];
  inquiryDisputes?: InquiryDisputeItem[];
}

const NEGATIVE_KEYWORDS = [
  'collection',
  'charge-off',
  'chargeoff',
  'late payment',
  'delinquent',
  'past due',
  'bankruptcy',
  'foreclosure',
  'repossession',
  'judgment',
  'tax lien',
  'settled',
  'written off',
];

const ACCOUNT_TYPE_PATTERNS: Record<string, RegExp> = {
  credit_card: /credit\s*card|revolving|visa|mastercard|amex|discover/i,
  auto_loan: /auto|vehicle|car\s*loan/i,
  mortgage: /mortgage|home\s*loan|real\s*estate/i,
  personal_loan: /personal\s*loan|installment/i,
  student_loan: /student|education|loan/i,
  collection: /collection|collect/i,
};

export async function parsePdfCreditReport(buffer: Buffer): Promise<ParsedCreditData> {
  const data = await parsePdf(buffer);
  const text = data.text;

  // Detect source service
  const detectedSource = detectPdfSource(text);
  console.log(`[PDF Parser] Detected source: ${detectedSource.source} (confidence: ${detectedSource.confidence})`);

  const scores = extractScores(text);
  const consumerProfile = extractConsumerProfile(text);
  const accounts = extractAccounts(text);
  const negativeItems = extractNegativeItems(text, accounts);
  const inquiries = extractInquiries(text);
  const summary = calculateSummary(accounts);

  return {
    scores,
    accounts,
    negativeItems,
    inquiries,
    summary,
    rawText: text,
    detectedSource,
    consumerProfile,
  };
}

function extractConsumerProfile(text: string): ParsedConsumerProfile {
  const profile: ParsedConsumerProfile = {
    names: [],
    addresses: [],
    employers: [],
  };

  // Extract names - look for patterns like "Name: John Doe" or "Consumer: John Doe"
  const namePatterns = [
    /(?:Name|Consumer|Applicant)[:\s]+([A-Z][a-zA-Z]+)\s+([A-Z]\.?\s+)?([A-Z][a-zA-Z]+)(?:\s+(JR|SR|II|III|IV))?/gi,
    /(?:Personal\s+Information)[\s\S]*?([A-Z][a-zA-Z]+)\s+([A-Z]\.?\s+)?([A-Z][a-zA-Z]+)/gi,
  ];

  for (const pattern of namePatterns) {
    const matches = text.matchAll(pattern);
    for (const match of matches) {
      const firstName = match[1];
      const middleName = match[2]?.trim().replace(/\.$/, '');
      const lastName = match[3];
      const suffix = match[4];

      if (firstName && lastName && !profile.names.some(n => n.firstName === firstName && n.lastName === lastName)) {
        profile.names.push({
          firstName,
          middleName: middleName || undefined,
          lastName,
          suffix: suffix || undefined,
        });
      }
    }
  }

  // Extract addresses
  const addressPattern = /(\d+[^,\n]+),\s*([A-Za-z\s]+),\s*([A-Z]{2})\s*(\d{5}(?:-\d{4})?)/g;
  const addressMatches = text.matchAll(addressPattern);
  for (const match of addressMatches) {
    const address = {
      street: match[1].trim(),
      city: match[2].trim(),
      state: match[3],
      zipCode: match[4],
    };

    if (!profile.addresses.some(a => a.street === address.street && a.zipCode === address.zipCode)) {
      profile.addresses.push(address);
    }
  }

  // Extract SSN last 4
  const ssnMatch = text.match(/(?:SSN|Social\s*Security)[:\s#]*(?:XXX-XX-|[\d*X]{3}-[\d*X]{2}-)?(\d{4})/i);
  if (ssnMatch) {
    profile.ssnLast4 = ssnMatch[1];
  }

  // Extract DOB
  const dobMatch = text.match(/(?:DOB|Date\s*of\s*Birth|Birth\s*Date)[:\s]*(\d{1,2}[-\/]\d{1,2}[-\/]\d{2,4})/i);
  if (dobMatch) {
    const date = new Date(dobMatch[1].replace(/-/g, '/'));
    if (!isNaN(date.getTime())) {
      profile.dateOfBirth = date;
    }
  }

  // Extract employers
  const employerPattern = /(?:Employer|Employment)[:\s]*([A-Z][A-Za-z0-9\s&.,'-]+?)(?:\s+(?:since|from|\d{1,2}[-\/]\d{1,2}[-\/]\d{2,4})|\n|$)/gi;
  const employerMatches = text.matchAll(employerPattern);
  for (const match of employerMatches) {
    const name = match[1].trim();
    if (name.length > 2 && name.length < 80 && !profile.employers.some(e => e.name === name)) {
      profile.employers.push({ name });
    }
  }

  return profile;
}

function extractScores(text: string): ParsedCreditData['scores'] {
  const scores: ParsedCreditData['scores'] = {};

  // TransUnion
  const tuMatch = text.match(/TransUnion[:\s]*(\d{3})/i);
  if (tuMatch) scores.transunion = parseInt(tuMatch[1]);

  // Experian
  const exMatch = text.match(/Experian[:\s]*(\d{3})/i);
  if (exMatch) scores.experian = parseInt(exMatch[1]);

  // Equifax
  const eqMatch = text.match(/Equifax[:\s]*(\d{3})/i);
  if (eqMatch) scores.equifax = parseInt(eqMatch[1]);

  // Generic score if no specific bureau found
  if (!scores.transunion && !scores.experian && !scores.equifax) {
    const genericMatch = text.match(/(?:FICO|VantageScore|Credit\s*Score)[:\s]*(\d{3})/i);
    if (genericMatch) {
      const score = parseInt(genericMatch[1]);
      scores.transunion = score;
      scores.experian = score;
      scores.equifax = score;
    }
  }

  return scores;
}

function extractAccounts(text: string): ParsedAccount[] {
  const accounts: ParsedAccount[] = [];

  // Split text into potential account sections
  const sections = text.split(/(?=Account\s*(?:Name|#|Number)|Creditor|Trade\s*Line)/i);

  for (const section of sections) {
    if (section.length < 50) continue;

    const account = parseAccountSection(section);
    if (account && account.creditorName) {
      accounts.push(account);
    }
  }

  return accounts;
}

function parseAccountSection(section: string): ParsedAccount | null {
  // Extract creditor name
  const nameMatch = section.match(/(?:Account\s*Name|Creditor|Company)[:\s]*([A-Z][A-Za-z0-9\s&.,'-]+)/i);
  if (!nameMatch) return null;

  const creditorName = nameMatch[1].trim().substring(0, 100);
  if (creditorName.length < 2) return null;

  // Extract account number (masked)
  const accountNumMatch = section.match(/(?:Account\s*(?:#|Number|No))[:\s]*([X\d*-]+)/i);
  const accountNumber = accountNumMatch ? accountNumMatch[1] : undefined;

  // Extract balance
  const balanceMatch = section.match(/(?:Balance|Current\s*Balance|Amount\s*Owed)[:\s]*\$?([\d,]+(?:\.\d{2})?)/i);
  const balance = balanceMatch ? Math.round(parseFloat(balanceMatch[1].replace(/,/g, '')) * 100) : undefined;

  // Extract credit limit
  const limitMatch = section.match(/(?:Credit\s*Limit|High\s*Credit|Limit)[:\s]*\$?([\d,]+(?:\.\d{2})?)/i);
  const creditLimit = limitMatch ? Math.round(parseFloat(limitMatch[1].replace(/,/g, '')) * 100) : undefined;

  // Extract payment status
  let paymentStatus = 'current';
  if (/30\s*days?\s*(?:late|past\s*due)/i.test(section)) paymentStatus = '30_days_late';
  else if (/60\s*days?\s*(?:late|past\s*due)/i.test(section)) paymentStatus = '60_days_late';
  else if (/90\s*days?\s*(?:late|past\s*due)/i.test(section)) paymentStatus = '90_days_late';
  else if (/120\s*days?\s*(?:late|past\s*due)/i.test(section)) paymentStatus = '120_days_late';
  else if (/collection/i.test(section)) paymentStatus = 'collection';

  // Determine account type
  let accountType = 'other';
  for (const [type, pattern] of Object.entries(ACCOUNT_TYPE_PATTERNS)) {
    if (pattern.test(section)) {
      accountType = type;
      break;
    }
  }

  // Determine account status
  let accountStatus = 'open';
  if (/closed/i.test(section)) accountStatus = 'closed';
  else if (/collection/i.test(section)) accountStatus = 'collection';
  else if (/charge[\s-]*off/i.test(section)) accountStatus = 'charge_off';

  // Check if negative
  const isNegative = NEGATIVE_KEYWORDS.some(keyword => 
    section.toLowerCase().includes(keyword.toLowerCase())
  );

  // Determine risk level
  let riskLevel = 'low';
  if (accountStatus === 'collection' || accountStatus === 'charge_off') riskLevel = 'severe';
  else if (paymentStatus !== 'current') {
    if (paymentStatus === '120_days_late') riskLevel = 'severe';
    else if (paymentStatus === '90_days_late') riskLevel = 'high';
    else if (paymentStatus === '60_days_late') riskLevel = 'medium';
    else riskLevel = 'low';
  }

  return {
    creditorName,
    accountNumber,
    accountType,
    accountStatus,
    balance,
    creditLimit,
    paymentStatus,
    isNegative,
    riskLevel,
  };
}

function extractNegativeItems(text: string, accounts: ParsedAccount[]): ParsedNegativeItem[] {
  const negativeItems: ParsedNegativeItem[] = [];

  // Add negative items from accounts
  for (const account of accounts) {
    if (account.isNegative) {
      let itemType = 'derogatory';
      if (account.accountStatus === 'collection') itemType = 'collection';
      else if (account.accountStatus === 'charge_off') itemType = 'charge_off';
      else if (account.paymentStatus?.includes('late')) itemType = 'late_payment';

      negativeItems.push({
        itemType,
        creditorName: account.creditorName,
        amount: account.balance,
        riskSeverity: account.riskLevel || 'medium',
      });
    }
  }

  // Look for additional negative items in text
  const collectionMatches = text.matchAll(/(?:Collection|Collector)[:\s]*([A-Za-z0-9\s&.,'-]+)[\s\S]{0,200}?\$?([\d,]+(?:\.\d{2})?)/gi);
  for (const match of collectionMatches) {
    const creditorName = match[1].trim().substring(0, 100);
    const amount = match[2] ? Math.round(parseFloat(match[2].replace(/,/g, '')) * 100) : undefined;

    if (!negativeItems.some(item => item.creditorName.toLowerCase() === creditorName.toLowerCase())) {
      negativeItems.push({
        itemType: 'collection',
        creditorName,
        amount,
        riskSeverity: 'high',
      });
    }
  }

  return negativeItems;
}

function extractInquiries(text: string): ParsedInquiry[] {
  const inquiries: ParsedInquiry[] = [];

  const inquirySection = text.match(/(?:Inquiries|Credit\s*Inquiries)[\s\S]*?(?=Account|Trade|$)/i);
  if (!inquirySection) return inquiries;

  const inquiryMatches = inquirySection[0].matchAll(/([A-Z][A-Za-z0-9\s&.,'-]+)\s+(\d{1,2}\/\d{1,2}\/\d{2,4})/g);
  for (const match of inquiryMatches) {
    inquiries.push({
      creditorName: match[1].trim(),
      inquiryDate: new Date(match[2]),
    });
  }

  return inquiries;
}

function calculateSummary(accounts: ParsedAccount[]): ParsedCreditData['summary'] {
  const openAccounts = accounts.filter(a => a.accountStatus === 'open');
  const closedAccounts = accounts.filter(a => a.accountStatus === 'closed');

  let totalDebt = 0;
  let totalCreditLimit = 0;

  for (const account of accounts) {
    if (account.balance) totalDebt += account.balance;
    if (account.creditLimit) totalCreditLimit += account.creditLimit;
  }

  const utilizationPercent = totalCreditLimit > 0 
    ? Math.round((totalDebt / totalCreditLimit) * 100) 
    : 0;

  return {
    totalAccounts: accounts.length,
    openAccounts: openAccounts.length,
    closedAccounts: closedAccounts.length,
    totalDebt,
    totalCreditLimit,
    utilizationPercent,
  };
}

