// IdentityIQ Credit Report Parser
// Handles HTML reports exported from IdentityIQ credit monitoring service
// Ported from PHP ParserController with IIQ-specific DOM selectors

import * as cheerio from 'cheerio';
import type { AnyNode } from 'domhandler';
import type {
  ParsedCreditData,
  ParsedAccount,
  ParsedNegativeItem,
  ParsedInquiry,
  BureauSummary,
  BureauMetrics,
  BureauCreditUtilization,
  CreditUtilization,
  DerogatoryAccount,
  PublicRecord,
  ExtendedParsedCreditData,
  PersonalInfoPerBureau,
  BureauPersonalInfo,
  PaymentHistorySummary,
  PersonalInfoDisputeType,
  PersonalInfoDisputeItem,
  InquiryDisputeItem,
} from './pdf-parser';
import {
  StandardizedAccount,
  StandardizedConsumerProfile,
  isAccountNegative,
  calculateRiskLevel,
} from './metro2-mapping';

// IdentityIQ-specific CSS selectors (matching actual HTML structure)
const IIQ_SELECTORS = {
  // Main sections
  creditScoreSection: '#CreditScore',
  summarySection: '#Summary',
  accountHistorySection: 'address-history',
  inquiriesSection: '#Inquiries',
  publicRecordsSection: '#PublicInformation',

  // Table structures
  fourColumnTable: 'table.rpt_content_table.rpt_table4column',
  accountTable: 'table.crPrint.ng-scope',
  dataTable: 'table.rpt_content_table.rpt_content_header.rpt_table4column.ng-scope',
  contactsTable: 'table.rpt_content_table.rpt_content_header.rpt_content_contacts',

  // Bureau header classes
  headerTransunion: '.headerTUC',
  headerExperian: '.headerEXP',
  headerEquifax: '.headerEQF',

  // Cell classes
  labelCell: 'td.label',
  infoCell: 'td.info',

  // Account headers
  accountHeader: 'div.sub_header.ng-binding.ng-scope',
  accountHeaderAlt: 'div.sub_header.ng-binding',

  // Content wrappers
  contentWrapper: '.rpt_content_wrapper',
  fullReportHeader: '.rpt_fullReport_header',

  // Two-year payment history
  paymentHistoryTable: 'table.rpt_content_table.addr_hsrty',
  paymentHistoryHeader: 'div.hstry-header.hstry-header-2yr',
};

// Derogatory detection patterns (from PHP)
const DEROGATORY_PATTERNS = [
  'collection/chargeoff',
  'chargeoff',
  'charge off',
  'late 30',
  'late 60',
  'late 90',
  'late 120',
  'late 150',
  'late 180',
];

// Bureau column indices (0-based, column 0 is label)
const BUREAU_COLUMNS = {
  transunion: 1,
  experian: 2,
  equifax: 3,
};

// Payment history CSS class patterns
const PAYMENT_HISTORY_CLASSES = {
  late30: 'hstry-30',
  late60: 'hstry-60',
  late90: 'hstry-90',
  late120: 'hstry-120',
  late150: 'hstry-150',
  late180: 'hstry-180',
  chargeOff: 'hstry-other',
  collection: 'hstry-co',
  ok: 'hstry-ok',
};

const IDENTITYIQ_PATTERNS = {
  dofd: /(?:date\s*of\s*first\s*delinquency|first\s*delinquency|dofd)\s*:?[\s\n]*(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})/i,
  removalDate: /(?:on\s*record\s*until|will\s*be\s*removed\s*by|scheduled\s*to\s*continue\s*until)\s*:?[\s\n]*(\d{1,2}[\/\-]\d{4}|\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})/i,
};

const BUREAU_LABELS: Record<'transunion' | 'experian' | 'equifax', string[]> = {
  transunion: ['transunion', 'tu', 'tuc'],
  experian: ['experian', 'exp'],
  equifax: ['equifax', 'eq', 'eqf'],
};

function createEmptyPaymentHistory(): PaymentHistorySummary {
  return {
    lateCount30: 0,
    lateCount60: 0,
    lateCount90: 0,
    lateCount120: 0,
    lateCount150: 0,
    lateCount180: 0,
    chargeOffCount: 0,
    collectionCount: 0,
    maxLateDays: 0,
  };
}

function computeMaxLateDays(history: PaymentHistorySummary): number {
  if (history.lateCount180 > 0 || history.chargeOffCount > 0 || history.collectionCount > 0) return 180;
  if (history.lateCount150 > 0) return 150;
  if (history.lateCount120 > 0) return 120;
  if (history.lateCount90 > 0) return 90;
  if (history.lateCount60 > 0) return 60;
  if (history.lateCount30 > 0) return 30;
  return 0;
}

function extractPaymentHistory(
  $: cheerio.CheerioAPI,
  $accountTable: cheerio.Cheerio<AnyNode>
): Record<'transunion' | 'experian' | 'equifax', PaymentHistorySummary> {
  const history: Record<'transunion' | 'experian' | 'equifax', PaymentHistorySummary> = {
    transunion: createEmptyPaymentHistory(),
    experian: createEmptyPaymentHistory(),
    equifax: createEmptyPaymentHistory(),
  };

  // Find payment history table within or after the account table
  // The structure varies: sometimes nested, sometimes sibling
  let $historyTable = $accountTable.find(IIQ_SELECTORS.paymentHistoryTable).first();

  if ($historyTable.length === 0) {
    // Try finding as a sibling after the account table
    $historyTable = $accountTable.nextAll(IIQ_SELECTORS.paymentHistoryTable).first();
  }

  if ($historyTable.length === 0) {
    return history;
  }

  // Parse payment history rows
  // Row structure: 
  //   Row 0: Month labels (headers)
  //   Row 1: TransUnion payment codes
  //   Row 2: Experian payment codes  
  //   Row 3: Equifax payment codes
  $historyTable.find('tr').each((rowIdx, row) => {
    // Skip header row (months)
    if (rowIdx === 0) return;

    // Map row index to bureau (rows 1-3 map to bureaus)
    let bureau: 'transunion' | 'experian' | 'equifax';
    if (rowIdx === 1) bureau = 'transunion';
    else if (rowIdx === 2) bureau = 'experian';
    else if (rowIdx === 3) bureau = 'equifax';
    else return;

    $(row).find('td.info').each((_, cell) => {
      const $cell = $(cell);
      const classes = $cell.attr('class') || '';

      // Check for each late status class
      if (classes.includes(PAYMENT_HISTORY_CLASSES.late30)) {
        history[bureau].lateCount30++;
      }
      if (classes.includes(PAYMENT_HISTORY_CLASSES.late60)) {
        history[bureau].lateCount60++;
      }
      if (classes.includes(PAYMENT_HISTORY_CLASSES.late90)) {
        history[bureau].lateCount90++;
      }
      if (classes.includes(PAYMENT_HISTORY_CLASSES.late120)) {
        history[bureau].lateCount120++;
      }
      if (classes.includes(PAYMENT_HISTORY_CLASSES.late150)) {
        history[bureau].lateCount150++;
      }
      if (classes.includes(PAYMENT_HISTORY_CLASSES.late180)) {
        history[bureau].lateCount180++;
      }
      // hstry-other typically indicates chargeoff/collection
      if (classes.includes(PAYMENT_HISTORY_CLASSES.chargeOff)) {
        history[bureau].chargeOffCount++;
      }
    });

    // Compute max late days for this bureau
    history[bureau].maxLateDays = computeMaxLateDays(history[bureau]);
  });

  return history;
}

export function parseIdentityIQReport(html: string): ExtendedParsedCreditData {
  const $ = cheerio.load(html);
  const text = $.text();

  // Extract all data using IIQ-specific methods
  const scores = extractIIQScores($);
  const bureauSummary = extractBureauSummary($);
  const bureauPersonalInfo = extractBureauPersonalInfo($);
  const consumerProfile = extractIIQConsumerProfile($);
  const { accounts, derogatoryAccounts } = extractIIQAccounts($);
  const creditUtilization = calculateCreditUtilization($);
  const publicRecords = extractPublicRecords($);
  const inquiries = extractIIQInquiries($);
  const negativeItems = buildNegativeItems(derogatoryAccounts, accounts);
  const personalInfoDisputes = buildPersonalInfoDisputes(bureauPersonalInfo);
  const inquiryDisputes = buildInquiryDisputes(inquiries);
  const summary = calculateIIQSummary(accounts, bureauSummary);

  return {
    scores,
    accounts,
    negativeItems,
    inquiries,
    summary,
    rawText: text,
    consumerProfile,
    bureauSummary,
    bureauPersonalInfo,
    creditUtilization,
    derogatoryAccounts,
    publicRecords,
    personalInfoDisputes,
    inquiryDisputes,
  } as ExtendedParsedCreditData;
}

function extractIIQScores($: cheerio.CheerioAPI): ParsedCreditData['scores'] {
  const scores: ParsedCreditData['scores'] = {};

  // Find the Credit Score section
  const $creditScoreSection = $(IIQ_SELECTORS.creditScoreSection);

  if ($creditScoreSection.length > 0) {
    // Find the 4-column table within the credit score section
    $creditScoreSection.find(IIQ_SELECTORS.fourColumnTable).each((_, table) => {
      const $table = $(table);

      $table.find('tr').each((_, row) => {
        const $row = $(row);
        const $cells = $row.find('td');

        if ($cells.length >= 4) {
          const labelText = $($cells[0]).text().trim().toLowerCase();

          if (labelText.includes('credit score')) {
            // Extract scores from each bureau column
            const tuScore = parseScore($($cells[BUREAU_COLUMNS.transunion]).text());
            const expScore = parseScore($($cells[BUREAU_COLUMNS.experian]).text());
            const eqScore = parseScore($($cells[BUREAU_COLUMNS.equifax]).text());

            if (tuScore) scores.transunion = tuScore;
            if (expScore) scores.experian = expScore;
            if (eqScore) scores.equifax = eqScore;
          }
        }
      });
    });
  }

  // Fallback: search all 4-column tables for credit score row
  if (!scores.transunion && !scores.experian && !scores.equifax) {
    $(IIQ_SELECTORS.fourColumnTable).each((_, table) => {
      const $table = $(table);

      $table.find('tr').each((_, row) => {
        const $row = $(row);
        const $cells = $row.find('td');

        if ($cells.length >= 4) {
          const labelText = $($cells[0]).text().trim().toLowerCase();

          if (labelText.includes('credit score') && !labelText.includes('factor')) {
            const tuScore = parseScore($($cells[1]).text());
            const expScore = parseScore($($cells[2]).text());
            const eqScore = parseScore($($cells[3]).text());

            if (tuScore && !scores.transunion) scores.transunion = tuScore;
            if (expScore && !scores.experian) scores.experian = expScore;
            if (eqScore && !scores.equifax) scores.equifax = eqScore;
          }
        }
      });
    });
  }

  return scores;
}

function extractBureauSummary($: cheerio.CheerioAPI): BureauSummary {
  const createEmptyMetrics = (): BureauMetrics => ({
    creditScore: undefined,
    lenderRank: undefined,
    scoreScale: undefined,
    reportDate: undefined,
    totalAccounts: 0,
    openAccounts: 0,
    closedAccounts: 0,
    delinquent: 0,
    derogatory: 0,
    collection: 0,
    balances: 0,
    payments: 0,
    publicRecords: 0,
    inquiries: 0,
  });

  const summary: BureauSummary = {
    transunion: createEmptyMetrics(),
    experian: createEmptyMetrics(),
    equifax: createEmptyMetrics(),
  };

  // Extract Credit Score, Lender Rank, Score Scale from Credit Score section
  extractCreditScoreData($, summary);

  // Extract Report Date from Personal Information section
  extractReportDates($, summary);

  // Find the Summary section for account counts
  const $summarySection = $(IIQ_SELECTORS.summarySection).closest(IIQ_SELECTORS.contentWrapper);

  if ($summarySection.length === 0) {
    // Fallback: find by header text
    $(IIQ_SELECTORS.contentWrapper).each((_, wrapper) => {
      const headerText = $(wrapper).find(IIQ_SELECTORS.fullReportHeader).text().toLowerCase();
      if (headerText.includes('summary')) {
        extractSummaryFromTable($, $(wrapper), summary);
      }
    });
  } else {
    extractSummaryFromTable($, $summarySection, summary);
  }

  return summary;
}

