import { describe, expect, it } from 'vitest';
import { __testOnly_getAccountPresence } from '@/lib/credit-analysis';
import type { ParsedAccount } from '@/lib/parsers/pdf-parser';

describe('credit account ingest bureau presence', () => {
  it('uses parser-provided bureau evidence for combined reports', () => {
    const account: ParsedAccount = {
      creditorName: 'Capital Bank',
      accountNumber: '***1111',
      accountType: 'Revolving',
      accountStatus: 'open',
      balance: 12345,
      isNegative: false,
      bureauEvidence: {
        transunion: {
          accountNumber: '***1111',
          balance: 12345,
          dateOpened: new Date('2020-01-15T00:00:00.000Z'),
        },
        equifax: {
          accountNumber: '***3333',
          balance: 45678,
          dateOpened: new Date('2021-02-20T00:00:00.000Z'),
        },
      },
    };

    expect(__testOnly_getAccountPresence(account, 'combined')).toEqual({
      onTransunion: true,
      onExperian: false,
      onEquifax: true,
      transunionDate: new Date('2020-01-15T00:00:00.000Z'),
      experianDate: undefined,
      equifaxDate: new Date('2021-02-20T00:00:00.000Z'),
      transunionBalance: 12345,
      experianBalance: undefined,
      equifaxBalance: 45678,
    });
  });

  it('falls back to legacy all-bureau behavior when parser evidence is absent', () => {
    const account: ParsedAccount = {
      creditorName: 'Capital Bank',
      accountNumber: '***1111',
      accountType: 'Revolving',
      accountStatus: 'open',
      balance: 12345,
      isNegative: false,
    };

    expect(__testOnly_getAccountPresence(account, 'combined')).toEqual({
      onTransunion: true,
      onExperian: true,
      onEquifax: true,
      transunionDate: undefined,
      experianDate: undefined,
      equifaxDate: undefined,
      transunionBalance: 12345,
      experianBalance: 12345,
      equifaxBalance: 12345,
    });
  });
});

